from dataclasses import dataclass, field
from enum import Enum


class LoopOutcome(Enum):
    CONTINUE = "continue"
    STOP_SUCCESS = "stop_success"
    STOP_BUDGET = "stop_budget"
    STOP_ERROR = "stop_error"
    ESCALATE = "escalate"


@dataclass
class LoopState:
    step: int = 0
    max_steps: int = 20
    consecutive_errors: int = 0
    max_consecutive_errors: int = 3
    final_answer: str = ""
    escalation_reason: str = ""

    def tick(self) -> None:
        self.step += 1

    def budget_exhausted(self) -> bool:
        return self.step >= self.max_steps

    def too_many_errors(self) -> bool:
        return self.consecutive_errors >= self.max_consecutive_errors


def decide_outcome(
    state: LoopState,
    stop_reason: str,
    has_tool_calls: bool,
    any_error: bool,
) -> LoopOutcome:
    """Pure function: determine what happens next after one loop step."""
    if any_error:
        state.consecutive_errors += 1
    else:
        state.consecutive_errors = 0

    if state.too_many_errors():
        return LoopOutcome.ESCALATE

    if stop_reason == "end_turn" and not has_tool_calls:
        return LoopOutcome.STOP_SUCCESS

    state.tick()
    if state.budget_exhausted():
        return LoopOutcome.STOP_BUDGET

    return LoopOutcome.CONTINUE

def trim_messages_to_token_budget(
    messages: list[dict],
    max_context_tokens: int = 180_000,
    tokens_per_char: float = 0.25,
) -> list[dict]:
    """
    Trim oldest assistant+user pairs when the context grows too large.
    Always keeps the original user task (messages[0]).
    """
    def rough_tokens(m: dict) -> int:
        content = m.get("content", "")
        if isinstance(content, str):
            return int(len(content) * tokens_per_char)
        # list of content blocks
        return int(sum(
            len(b.get("content", b.get("text", ""))) * tokens_per_char
            for b in content
            if isinstance(b, dict)
        ))

    while len(messages) > 1:
        total = sum(rough_tokens(m) for m in messages)
        if total <= max_context_tokens:
            break
        # Drop the second message (oldest non-task turn) to preserve the task
        messages = [messages[0]] + messages[2:]

    return messages


